// Auto-generated pixel-art product/tank icons (base64 PNG data-uris) for ห้วยบอนแก๊ส app.
// Loaded as a plain classic <script> before the main app script so PRODUCT_ICONS etc. are global.
const PRODUCT_ICONS = {
  tank_regular_4: 'data:image/png;base64,',
  tank_regular_7: 'data:image/png;base64,',
  tank_regular_15: 'data:image/png;base64,',
  tank_regular_48: 'data:image/png;base64,',
  tank_ptt_4: 'data:image/png;base64,',
  tank_ptt_7: 'data:image/png;base64,',
  tank_ptt_15: 'data:image/png;base64,',
  tank_ptt_48: 'data:image/png;base64,',
  op_milk: 'data:image/png;base64,',
  op_showerhead: 'data:image/png;base64,',
  op_frame4kg: 'data:image/png;base64,',
  op_valve: 'data:image/png;base64,',
  op_regulator: 'data:image/png;base64,',
  op_tank15_new: 'data:image/png;base64,',
  op_hose: 'data:image/png;base64,',
  op_clamp: 'data:image/png;base64,',
};
const PRODUCT_ID_ICON_KEY = {
  op_milk: 'op_milk',
  op_showerhead: 'op_showerhead',
  op_frame4kg: 'op_frame4kg',
  op_valve: 'op_valve',
  op_regulator: 'op_regulator',
  op_hose: 'op_hose',
  op_clamp: 'op_clamp',
  op_tank15_regular: 'op_tank15_new',
  op_tank15_ptt: 'tank_ptt_15',
  op_tank4_regular: 'tank_regular_4',
  op_tank4_ptt: 'tank_ptt_4',
};
// returns a base64 data-uri pixel-art icon for a given gas size+brand, or '' if unavailable
function tankIconSrc(brand, size){
  const key = 'tank_' + (brand==='ptt'?'ptt':'regular') + '_' + size;
  return PRODUCT_ICONS[key] || '';
}
// returns a base64 data-uri pixel-art icon for a non-gas otherProducts catalog id, or '' if unavailable
function productIconSrc(productId){
  const key = PRODUCT_ID_ICON_KEY[productId];
  return key ? (PRODUCT_ICONS[key] || '') : '';
}
// small <img> helper, returns '' (renders nothing) if src is missing so callers can safely inline it
function iconImgHtml(src, size){
  size = size || 32;
  if(!src) return '';
  return '<img src="' + src + '" style="width:' + size + 'px;height:' + size + 'px;image-rendering:pixelated;border-radius:6px;vertical-align:middle;flex-shrink:0;">';
}
